# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, session, jsonify
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.secret_key = 'your-secret-key'

# Mock user data storage
users = {
    'user1': {
        'email': 'user@example.com',
        'password': generate_password_hash('oldpassword'),
        'two_factor_enabled': False
    }
}

@app.route('/profile', methods=['POST'])
def update_profile():
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401
    
    user_id = session['user_id']
    user = users.get(user_id)
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    data = request.get_json()
    
    # Update email
    if 'email' in data:
        user['email'] = data['email']
    
    # Update password
    if 'password' in data:
        if not check_password_hash(user['password'], data.get('current_password', '')):
            return jsonify({'error': 'Current password is incorrect'}), 400
        user['password'] = generate_password_hash(data['password'])
    
    # Update 2FA settings
    if 'two_factor_enabled' in data:
        user['two_factor_enabled'] = bool(data['two_factor_enabled'])
    
    return jsonify({'message': 'Profile updated successfully'})

if __name__ == '__main__':
    app.run(debug=True)